24	async function bootstrap(): Promise<NestFastifyApplication> {
25		const port = getEnv<number>({ key: PORT, converter: Number });
26		const globalPrefix = getEnv<string>({ key: GLOBAL_PREFIX });
27		const nodeEnv = getEnv<Environment>({ key: NODE_ENV });
28		const isDev = nodeEnv === Environment.DEVELOPMENT;
29	
30		const fastifyAdapter = new FastifyAdapter({ trustProxy: true });
31	
32		const app = await NestFactory.create<NestFastifyApplication>(
33			AppModule,
34			fastifyAdapter,
35			{
36				logger: isDev
37					? ['log', 'error', 'warn', 'fatal', 'debug', 'verbose']
38					: ['log', 'error', 'warn', 'fatal'],
39			},
40		);
41	
42		await app.register(fastifyCookie);
43	
44		app.enableCors({
45			origin: getEnv<string>({ key: FRONTEND_URL }),
46			credentials: true,
47		});
48	
49		app.useGlobalPipes(
50			new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
51		);
52	
53		app.setGlobalPrefix(globalPrefix, {
54			exclude: ['liveness', 'readiness'],
55		});
56	
57		setupSwagger({ app, fastifyAdapter, globalPrefix });
58	
59		if (!isDev) {
60			app.enableShutdownHooks();
61		}
62	
63		await app.listen(port, '0.0.0.0');
64	
65		Logger.log(`Application running on port ${String(port)}`, 'Bootstrap');
66	
67		return app;
68	}
69	
70	let app: NestFastifyApplication | undefined;
71	
72	async function startApp(): Promise<void> {
73		try {
74			app = await bootstrap();
75		} catch (err: unknown) {
76			Logger.error('Failed to start application', err, 'Bootstrap');
77			process.exit(1);
78		}
79	}
80	
81	void startApp();
82	
83	if (module.hot) {
84		module.hot.accept();
85		module.hot.dispose(() => {
86			void app?.close();
87		});
88	}
